mapper.select:
SELECT
    ids.id,
    t.name AS deviceName,
    f.name AS feederName
FROM (

        SELECT #{id} AS id

) ids
LEFT JOIN (
    SELECT id, name, feeder_id FROM ies_ms.aclinesegment_b WHERE id IN

        #{id}

    UNION ALL
    SELECT id, name, feeder_id FROM ies_ms.breaker_b WHERE id IN

        #{id}

    UNION ALL
    SELECT id, name, feeder_id FROM ies_ms.fuse_b WHERE id IN

        #{id}

    UNION ALL
    SELECT id, name, feeder_id FROM ies_ms.dmstransformer_b WHERE id IN

        #{id}

    UNION ALL
    SELECT id, name, feeder_id FROM ies_ms.disconnector_b WHERE id IN

        #{id}

    UNION ALL
    SELECT id, name, feeder_id FROM ies_ms.Pole_B WHERE id IN

        #{id}

    UNION ALL
    SELECT id, name, feeder_id FROM ies_ms.FaultIndicator_B WHERE id IN

        #{id}

    UNION ALL
    SELECT id, name, feeder_id FROM ies_ms.Junction_B WHERE id IN

        #{id}

    UNION ALL
    SELECT id, name, feeder_id FROM ies_ms.compositeswitch_b WHERE id IN

        #{id}

) t ON ids.id = t.id
LEFT JOIN ies_ms.feeder_b f ON t.feeder_id = f.id
